{
  "fixed_code": [
    "private void checkInterfaceConflictProperties(NodeTraversal t, Node n,
      String functionName, HashMap<String, ObjectType> properties,
      HashMap<String, ObjectType> currentProperties,
      ObjectType interfaceType) {
    ObjectType implicitProto = interfaceType.getImplicitPrototype();
    Set<String> currentPropertyNames;
    // This can be the case if interfaceType is proxy to a non-existent
    // object (which is a bad type annotation, but shouldn't crash).
    if (implicitProto == null) {
      currentPropertyNames = java.util.Collections.<String>emptySet();
    } else {
      currentPropertyNames = implicitProto.getOwnPropertyNames();
    }
    for (String name : currentPropertyNames) {
      ObjectType oType = properties.get(name);
      if (oType != null) {
        if (!interfaceType.getPropertyType(name).isEquivalentTo(
            oType.getPropertyType(name))) {
          compiler.report(
              t.makeError(n, INCOMPATIBLE_EXTENDED_PROPERTY_TYPE,
                  functionName, name, oType.toString(),
                  interfaceType.toString()));
        }
      }
      currentProperties.put(name, interfaceType);
    }
    Iterable<ObjectType> extended = interfaceType.getCtorExtendedInterfaces();
    if (extended != null) {
      for (ObjectType iType : extended) {
        checkInterfaceConflictProperties(t, n, functionName, properties,
            currentProperties, iType);
      }
    }
  }"
  ],
  "additional_testcases": []
}

{
  "fixed_code": [
    "private Node tryFoldSimpleFunctionCall(Node n) {
    Preconditions.checkState(n.isCall());
    Node callTarget = n.getFirstChild();
    if (callTarget != null && callTarget.isName() &&
          callTarget.getString().equals("String")) {
      // Fold String(a) to '' + (a) only when there is exactly one argument
      // and it is an immutable literal. This avoids changing semantics for
      // objects or multiple-argument calls.
      Node value = callTarget.getNext();
      // Ensure exactly one argument
      if (value != null && value.getNext() == null) {
        // Check for immutable literal: string, number, boolean, or null
        boolean isImmutable = value.isString() || value.isNumber() ||
            value.isTrue() || value.isFalse() || value.isNull();
        if (isImmutable) {
          Node addition = IR.add(
              IR.string("").srcref(callTarget),
              value.detachFromParent());
          n.getParent().replaceChild(n, addition);
          reportCodeChange();
          return addition;
        }
      }
    }
    return n;
  }"
  ],
  "additional_testcases": [
    {
      "path": "com/google/javascript/jscomp/PeepholeSubstituteAlternateSyntaxTest.java::testSimpleFunctionCall",
      "testcase": "testSame("var a = String({});");"
    }
  ]
}

{
  "fixed_code": [
    "public void visit(NodeTraversal t, Node n, Node parent) {
    // VOID nodes appear when there are extra semicolons at the BLOCK level.
    // Allow extra semicolons at the BLOCK level only.
    if (n.isEmpty()) {
      if (parent != null && parent.getType() == Token.BLOCK) {
        return;
      }
      // otherwise, allow further checks to report useless empty statements
    } else if (n.isComma()) {
      return;
    }

    if (parent == null) {
      return;
    }

    // Do not try to remove a block or an expr result. We already handle
    // these cases when we visit the child, and the peephole passes will
    // fix up the tree in more clever ways when these are removed.
    if (n.isExprResult()) {
      return;
    }

    // This no-op statement was there so that JSDoc information could
    // be attached to the name. This check should not complain about it.
    if (n.isQualifiedName() && n.getJSDocInfo() != null) {
      return;
    }

    boolean isResultUsed = NodeUtil.isExpressionResultUsed(n);
    boolean isSimpleOp = NodeUtil.isSimpleOperatorType(n.getType());
    if (parent.getType() == Token.COMMA) {
      if (isResultUsed) {
        return;
      }
      if (n == parent.getLastChild()) {
        for (Node an : parent.getAncestors()) {
          int ancestorType = an.getType();
          if (ancestorType == Token.COMMA) continue;
          if (ancestorType != Token.EXPR_RESULT && ancestorType != Token.BLOCK) return;
          else break;
        }
      }
    } else if (parent.getType() != Token.EXPR_RESULT && parent.getType() != Token.BLOCK) {
      if (! (parent.getType() == Token.FOR && parent.getChildCount() == 4 && (n == parent.getFirstChild() || n == parent.getFirstChild().getNext().getNext())) && !n.isEmpty()) {
        return;
      }
    }
    if (
        (isSimpleOp || !NodeUtil.mayHaveSideEffects(n, t.getCompiler()))) {
      String msg = "This code lacks side-effects. Is there a bug?";
      if (n.isString()) {
        msg = "Is there a missing '+' on the previous line?";
      } else if (isSimpleOp) {
        msg = "The result of the '" + Token.name(n.getType()).toLowerCase() +
            "' operator is not being used.";
      }

      t.getCompiler().report(
          t.makeError(n, level, USELESS_CODE_ERROR, msg));
      // TODO(johnlenz): determine if it is necessary to
      // try to protect side-effect free statements as well.
      if (!NodeUtil.isStatement(n)) {
        problemNodes.add(n);
      }
    }
  }"
  ],
  "additional_testcases": [
    {
      "path": "com/google/javascript/jscomp/CheckSideEffectsTest.java::testUselessCode",
      "testcase": "test("if(x);", "if(x);", e);"
    }
    ]
}

{
  "fixed_code": [
    "public void visit(NodeTraversal t, Node n, Node parent) {
    // VOID nodes appear when there are extra semicolons at the BLOCK level.
    // I've been unable to think of any cases where this indicates a bug,
    // and apparently some people like keeping these semicolons around,
    // so we'll allow it.
    if (n.isEmpty() || n.isComma()) {
      return;
    }

    if (parent == null) {
      return;
    }

    // Do not try to remove a block or an expr result. We already handle
    // these cases when we visit the child, and the peephole passes will
    // fix up the tree in more clever ways when these are removed.
    if (parent.getType() == Token.COMMA) {
      Node gramps = parent.getParent();
      if (gramps != null && gramps.isCall() && parent == gramps.getFirstChild()) {
        // Allow patterns like (something, eval)(...)
        if (n == parent.getFirstChild()
            && parent.getChildCount() == 2
            && n.getNext().isName()
            && "eval".equals(n.getNext().getString())) {
          return;
        }
      }

      // This no-op statement was there so that JSDoc information could
      // be attached to the name. This check should not complain about it.
      if (n == parent.getLastChild()) {
        for (Node an : parent.getAncestors()) {
          int ancestorType = an.getType();
          if (ancestorType == Token.COMMA) {
            continue;
          }
          if (ancestorType != Token.EXPR_RESULT && ancestorType != Token.BLOCK) {
            return;
          } else {
            break;
          }
        }
      }
    } else if (parent.getType() != Token.EXPR_RESULT && parent.getType() != Token.BLOCK) {
      if (parent.getType() == Token.FOR && parent.getChildCount() == 4 &&
          (n == parent.getFirstChild() || n == parent.getFirstChild().getNext().getNext())) {
        // Allow analysis in FOR init and update positions.
      } else {
        return;
      }
    }

    boolean isResultUsed = NodeUtil.isExpressionResultUsed(n);
    boolean isSimpleOp = NodeUtil.isSimpleOperatorType(n.getType());
    if (!isResultUsed && (isSimpleOp || !NodeUtil.mayHaveSideEffects(n, t.getCompiler()))) {
      if (n.isQualifiedName() && n.getJSDocInfo() != null) {
        return;
      } else if (n.isExprResult()) {
        return;
      }
      String msg = "This code lacks side-effects. Is there a bug?";
      if (n.isString()) {
        msg = "Is there a missing '+' on the previous line?";
      } else if (isSimpleOp) {
        msg = "The result of the '" + Token.name(n.getType()).toLowerCase() +
            "' operator is not being used.";
      }

      t.getCompiler().report(
          t.makeError(n, level, USELESS_CODE_ERROR, msg));
      // TODO(johnlenz): determine if it is necessary to
      // try to protect side-effect free statements as well.
      if (!NodeUtil.isStatement(n)) {
        problemNodes.add(n);
      }
    }
  }"
